use std::collections::BinaryHeap;

fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len() as i64;
    let mut adj = vec![vec![]; n as usize];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let cost = edge[2];
        adj[u].push((v as i64, cost));
    }

    let mut best_min = vec![i64::MIN; n as usize];
    best_min[0 as usize] = i64::MAX;

    let mut heap = BinaryHeap::new();
    heap.push((-i64::MAX, 0, 0));

    while let Some((neg_current_min, total_cost, node)) = heap.pop() {
        let current_min = -neg_current_min;
        let node = node as usize;
        if node == (n - 1) as usize {
            return current_min;
        }
        if current_min < best_min[node] {
            continue;
        }
        for (v, cost) in adj[node] {
            let v = v as usize;
            if !online[v] {
                continue;
            }
            let new_total = total_cost + cost;
            if new_total > k {
                continue;
            }
            let new_min = std::cmp::min(current_min, cost);
            if new_min > best_min[v] {
                best_min[v] = new_min;
                heap.push((-new_min, new_total, v as i64));
            }
        }
    }

