fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {

    let n = online.len();

    if n == 0 {

        return -1;

    }

    // Compute topological order

    let top_order = topological_sort(n, &edges);

    // Compute max edge cost

    let mut max_edge = 0;

    for edge in &edges {

        let cost = edge[2];

        if cost > max_edge {

            max_edge = cost;

        }

    }

    // Binary search

    let mut low = 0;

    let mut high = max_edge;

    let mut ans = -1;

    while low <= high {

        let mid = (low + high) / 2;

        if is_possible(mid, &edges, &online, &top_order, k, n) {

            ans = mid;

            low = mid + 1;

        } else {

            high = mid - 1;

        }

    }

    ans

}

